(() => {

  const ready = appsmith.store.deptReady;

  const allDepts = GetDepartments.data || [];
  const ctx = appsmith.store.userContext;
  const signOffs = GetDepartmentSignOff.data || [];
  const selectedPO = appsmith.store.selectedPO;

  if (!ready || !allDepts.length || !ctx) return [];

  // 🔹 user departments
  const userDeps = (ctx.departments || [])
    .map(d => d?.trim().toLowerCase())
    .filter(Boolean);

  // 🔹 get ALL departments sorted by RunOrder
  const ordered = [...allDepts]
    .sort((a, b) => Number(a.RunOrder) - Number(b.RunOrder));

  // 🔥 find FIRST unsigned department
  const nextDept = ordered.find(d => {

    const dept = d.Department?.trim().toLowerCase();

    const isSigned = signOffs.some(s =>
      s.MicrossSalesOrderReference === selectedPO &&
      Number(s.SignedOff) === 1 &&
      s.Department?.trim().toLowerCase() === dept
    );

    return !isSigned;

  });

  if (!nextDept) return []; // everything signed

  const nextDeptName = nextDept.Department?.trim().toLowerCase();

  // 🔥 ONLY return it if user belongs to it
  if (!userDeps.includes(nextDeptName)) {
    return [{
      label: "Waiting for previous department",
      value: ""
    }];
  }

  return [{
    label: nextDept.Department,
    value: nextDept.Department
  }];

})()
}}
